// Input: {tenant_id, correlation_id, service, step, status, payload}
// Normalize + validate before insert. payload is stringified to JSONB-safe object.
const in0 = ($input.first().json) || {};
const payload = in0.payload == null ? {} : in0.payload;
return [{
  json: {
    tenant_id: in0.tenant_id || null,
    correlation_id: in0.correlation_id,
    service: in0.service || 'unknown',
    step: in0.step || 'unknown',
    status: in0.status || 'started',
    payload: (typeof payload === 'string') ? JSON.parse(payload) : payload
  }
}];

